  return await page.evaluate(() => {
    const list = document.querySelector('ol');
    if (!list) return { error: 'no list' };
    const entries = Array.from(list.querySelectorAll(':scope > li')).map((li, idx) => {
      const userAnchor = li.querySelector('h3 a[href^="/"]') || li.querySelector('a[data-hovercard-type="user"]') || li.querySelector('a[href^="/"]');
      const username = userAnchor ? userAnchor.getAttribute('href')?.replace(/^\//,'').split('?')[0] : null;
      const text = li.textContent?.replace(/\s+/g, ' ').trim() || '';
      const commitMatch = text.match(/([\d,]+)\s+commits?/i);
      const commits = commitMatch ? commitMatch[1] : null;
      return { rank: idx + 1, username, commits, text: text.slice(0,200) };
    });
    return { count: entries.length, top10: entries.slice(0,10) };
  });
}

